import{_ as a,v as t,f as r,i as o}from"./chunks/framework.jfF5glnW.js";const _=JSON.parse('{"title":"Week 5 | 3D 建模到 3D 打印实物","description":"","frontmatter":{"title":"Week 5 | 3D 建模到 3D 打印实物","date":"2026-03-31T00:00:00.000Z","tags":["课程周志","3D建模","3D打印"],"cover":"/code2real_blog/posts/week5/cat.webp"},"headers":[],"relativePath":"posts/week5.md","filePath":"posts/week5.md"}'),s={name:"posts/week5.md"};function p(i,e,l,n,c,d){return t(),r("div",null,[...e[0]||(e[0]=[o('<p>第五周把前面完成的数字模型推进到实体输出阶段。本周围绕“饮水思源”模型进行结构整理、打印准备和 3D 打印尝试。</p><hr><img src="/code2real_blog/posts/week5/cat.webp" alt="Week 5 image"><h2 id="本周学习内容" tabindex="-1">本周学习内容 <a class="header-anchor" href="#本周学习内容" aria-label="Permalink to &quot;本周学习内容&quot;">​</a></h2><p>本周的重点不再只是完成三维模型，而是判断模型能不能被实际打印。建模软件里能显示的结构，不一定适合直接制造。壁厚、悬空结构、支撑、打印方向和细节尺寸都会影响最终成品。</p><p>围绕“饮水思源”模型，主要学习了模型检查、导出文件、切片准备和打印参数的基本概念。层高、填充率、支撑方式和摆放方向虽然都是打印前的设置，但它们会直接改变成品质量。</p><h2 id="实践过程" tabindex="-1">实践过程 <a class="header-anchor" href="#实践过程" aria-label="Permalink to &quot;实践过程&quot;">​</a></h2><p>实践中先对模型结构进行检查。该模型包含底座、主体框架、文字装饰和顶部轮廓，局部结构比较细，因此需要判断哪些地方容易断、哪些部分需要支撑，哪些文字或装饰在打印尺寸下可能无法保留。</p><p>之后进入切片准备阶段，尝试从打印角度重新观察模型。以前建模时主要看外形是否完整，这一周开始关注模型与平台的接触面积、重心位置、悬空角度和支撑拆除后的表面效果。</p><h2 id="遇到的问题" tabindex="-1">遇到的问题 <a class="header-anchor" href="#遇到的问题" aria-label="Permalink to &quot;遇到的问题&quot;">​</a></h2><p>本周最主要的问题是造型效果和打印稳定性之间存在冲突。有些结构在屏幕上看起来更精细，但实际打印时可能因为太薄、太高或支撑不足而失败。为了提高成功率，又不能把结构简化得过多，否则模型原本的表达会被削弱。</p><p>打印方向也是一个需要反复判断的问题。不同摆放方式会改变支撑数量、表面纹理和局部细节保留程度。这个过程不能只按建模时的观察角度来决定，而要结合打印机的工作方式重新分析。</p><h2 id="本周收获" tabindex="-1">本周收获 <a class="header-anchor" href="#本周收获" aria-label="Permalink to &quot;本周收获&quot;">​</a></h2><p>本周最大的收获是理解了“能建出来”和“能做出来”之间的差距。数字模型只是设计结果，打印过程才会真正检验结构是否可靠。</p><p>通过这次从建模到打印的转换，我开始把制造条件提前放进设计过程。后续再建模时，不能等到最后才考虑打印，而应该在结构设计阶段就预留厚度、支撑和装配空间。</p>',15)])])}const k=a(s,[["render",p]]);export{_ as __pageData,k as default};
